const id = parseInt(pathValue.id, 10);
const item = _.find(db.items, { id });
if (!item) throwError('Todo not found', 404);
return item;

if (!data || typeof data.title !== 'string' || !data.title.trim()) throwError('title is required', 400);
const nextId = (_.maxBy(db.items, 'id')?.id ?? 0) + 1;
const created = { id: nextId, title: data.title, done: !!data.done };
db.items.push(created);
setExitCode(201);
return created;

const id = parseInt(pathValue.id, 10);
const idx = _.findIndex(db.items, { id });
if (idx < 0) throwError('Todo not found', 404);
db.items[idx] = { ...db.items[idx], ...data, id };
return db.items[idx];

const id = parseInt(pathValue.id, 10);
const before = db.items.length;
db.items = db.items.filter(t => t.id !== id);
if (db.items.length === before) throwError('Todo not found', 404);
setExitCode(204);
